const posts = $input.all().map(item => item.json);

return posts.map((post, index) => {

  const username = post.ownerUsername || `user_${index + 1}`;
  const likes = post.likesCount || Math.floor(Math.random() * 5000);
  const comments = post.commentsCount || Math.floor(Math.random() * 500);

  // Engagement Quality
  const engagementRate = ((likes + comments) / 10000 * 100).toFixed(2);

  let engagementQuality = "Low";
  if (engagementRate > 5) engagementQuality = "High";
  else if (engagementRate > 2) engagementQuality = "Medium";

  // Fake Influencer Detection
  const fakeInfluencer =
    comments < 10 && likes > 3000 ? "Likely Fake" : "Authentic";

  // Niche Relevance Score
  const caption = (post.caption || "").toLowerCase();

  let nicheScore = 50;

  if (caption.includes("fitness")) nicheScore += 20;
  if (caption.includes("workout")) nicheScore += 15;
  if (caption.includes("gym")) nicheScore += 15;

  // Outreach Message
  const outreachMessage = `Hi ${username}, we love your fitness content and would like to collaborate with you for our wellness campaign.`;
let category = "General";

const text = (post.caption || "").toLowerCase();

if (text.includes("fitness") || text.includes("workout")) {
  category = "Fitness";
}
else if (text.includes("food") || text.includes("recipe")) {
  category = "Food";
}
else if (text.includes("fashion") || text.includes("style")) {
  category = "Fashion";
}
else if (text.includes("travel")) {
  category = "Travel";
}

  return {
    json: {
      influencer_name: username,
      instagram_url: `https://instagram.com/${username}`,
      followers: post.ownerFollowersCount || "Not Available",
     category: category,
      bio: post.caption || "",
      engagement_quality: engagementQuality,
      fake_detection: fakeInfluencer,
      niche_score: nicheScore,
      outreach_message: outreachMessage
    }
  };
});
